+export function createDeferred(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            // Reserve a real id now so deferred entities can be used as relation targets.
+            const entity = createEntity(world);
+            const buffer = current(world);
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current(world).commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current(world).commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current(world).commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) {
+            current(world).commands.push({ type: 'exclusive', entity, traits });
+        },
+        flush() { flushDeferred(world); },
+    };
+}
+
+export function enterDeferredScope(world: World) { buffers(world).push({ commands: [], spawned: new Set() }); }
+export function exitDeferredScope(world: World) {
+    flushDeferred(world);
