+export function flushDeferredEntity(world: World, entity: Entity) {
+    if (world[$internal].isFlushingDeferred) return;
+    // A command can only affect one entity directly. Flush all scopes in order to
+    // preserve ordering when an immediate mutation observes that entity.
+    if (buffers(world).some((b) => b.commands.some((c) => c.entity === entity))) flushDeferred(world);
+}
+
+export function flushDeferred(world: World) {
+    const buffer = current(world);
+    if (!buffer.commands.length) return;
+    const ctx = world[$internal];
+    ctx.isFlushingDeferred = true;
+    try {
+        for (const command of buffer.commands) {
+            if (command.type === 'destroy' && command.entity === ctx.worldEntity) {
+                throw new Error('Koota: The world entity cannot be destroyed through a deferred command.');
+            }
+            if (!world.has(command.entity)) continue;
+            switch (command.type) {
+                case 'spawn': applyAdd(world, command.entity, command.traits); break;
+                case 'add': applyAdd(world, command.entity, command.traits); break;
+                case 'remove': removeTrait(world, command.entity, ...command.traits); break;
+                case 'exclusive':
+                    for (const pair of command.traits) {
+                        const relation = pair[$internal].relation;
+                        removeTrait(world, command.entity, relation('*'));
+                        if (pair[$internal].target !== '*') applyAdd(world, command.entity, [pair]);
+                    }
+                    break;
+                case 'destroy': destroyEntity(world, command.entity); break;
+            }
+        }
+    } finally {
+        buffer.commands.length = 0;
+        buffer.spawned.clear();
+        ctx.isFlushingDeferred = false;
+    }
+}
+
+function applyAdd(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    for (const config of traits) {
+        addTrait(world, entity, config);
+        // Deferred writes are commands, rather than the immediate add-if-absent API:
+        // later supplied values therefore win for the same trait/pair.
+        if (Array.isArray(config)) setTrait(world, entity, config[0], config[1], false);
+        else if (isRelationPair(config) && config[$internal].params) {
+            setTrait(world, entity, config, config[$internal].params, false);
+        }
+    }
+}
+
+function commandsFor(world: World, entity: Entity): Command[] {
+    return buffers(world).flatMap((buffer) => buffer.commands.filter((command) => command.entity === entity));
+}
+
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    let alive = world.has(entity);
+    let present = isRelationPair(trait)
+        ? trait[$internal].target === '*'
+            ? getRelationTargets(world, trait[$internal].relation, entity).length > 0
+            : entity.has(trait)
+        : hasTrait(world, entity, trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') alive = false;
+        if (command.type === 'spawn') {
+            alive = true;
+            present = contains(command.traits, trait) || present;
+        }
+        if (command.type === 'add') present = contains(command.traits, trait) || present;
+        if (command.type === 'remove' && command.traits.some((t) => matches(t, trait))) present = false;
+        if (command.type === 'exclusive' && isRelationPair(trait)) {
+            const relation = trait[$internal].relation;
+            if (command.traits.some((p) => p[$internal].relation === relation)) {
+                present = command.traits.some((p) => matches(p, trait));
+            }
+        }
+    }
+    return alive && present;
+}
+
+export function deferredGet<T extends Trait | RelationPair>(world: World, entity: Entity, trait: T): TraitRecord<ExtractSchema<T>> | undefined | null {
+    const has = deferredHas(world, entity, trait);
+    if (has === undefined) return null;
+    if (!has) return undefined;
+    let value: any = getTrait(world, entity, trait);
+    for (const command of commandsFor(world, entity)) {
+        const configs = command.type === 'spawn' || command.type === 'add' ? command.traits : command.type === 'exclusive' ? command.traits : [];
+        for (const config of configs) {
+            if (!matches(config, trait)) continue;
+            const params = Array.isArray(config) ? config[1] : isRelationPair(config) ? config[$internal].params : undefined;
+            if (params) value = { ...(value ?? {}), ...params };
+        }
+    }
+    return value;
+}
+
+function contains(configs: readonly ConfigurableTrait[], target: Trait | RelationPair) { return configs.some((config) => matches(config, target)); }
+function matches(config: ConfigurableTrait | Trait | RelationPair, target: Trait | RelationPair) {
+    const a: any = Array.isArray(config) ? config[0] : config;
+    if (isRelationPair(a) || isRelationPair(target)) {
+        if (!isRelationPair(a) || !isRelationPair(target)) return false;
+        return a[$internal].relation === target[$internal].relation &&
+            (target[$internal].target === '*' || a[$internal].target === target[$internal].target);
+    }
+    return a === target;
+}
